// Check if the data looks like FP16 by inspecting bit patterns
// FP16 values in range [0.5, 1.5] have specific exponent bits
__device__ __host__ inline bool is_fp16_data(const void* ptr) {
    // Read first value as both FP32 and FP16
    const float* fp32_ptr = reinterpret_cast<const float*>(ptr);
    const __half* fp16_ptr = reinterpret_cast<const __half*>(ptr);

    // Convert FP16 interpretation to FP32
    float val_as_fp16 = __half2float(fp16_ptr[0]);
    float val_as_fp32 = fp32_ptr[0];

    // For running_var which should be in [0.5, 1.5]:
    // - If data is actually FP16, val_as_fp16 will be in reasonable range
    // - If data is actually FP32 but read as FP16, it will likely be way off

    // Check if FP16 interpretation gives reasonable value
    bool fp16_reasonable = (val_as_fp16 > 0.1f && val_as_fp16 < 10.0f) && isfinite(val_as_fp16);

    // Check if FP32 interpretation gives reasonable value
    bool fp32_reasonable = (val_as_fp32 > 0.1f && val_as_fp32 < 10.0f) && isfinite(val_as_fp32);

    // If both seem reasonable, use a secondary check: FP16 has 16-bit alignment patterns
    if (fp16_reasonable && fp32_reasonable) {
        // Check second value
        float val2_as_fp16 = __half2float(fp16_ptr[1]);
        float val2_as_fp32 = fp32_ptr[1];

        // FP16 values should both be reasonable
        bool both_fp16_ok = fp16_reasonable && 
                           (val2_as_fp16 > 0.1f && val2_as_fp16 < 10.0f) && 
                           isfinite(val2_as_fp16);

        return both_fp16_ok && (!fp32_reasonable || fabsf(val_as_fp32) > 100.0f);
